title: $:/plugins/cdr/markdown-more/markdown-it-admonition.js
type: application/javascript
module-type: library

Adds admonition container:

:::category optional title string
admonition body
:::
\*/
(function(){

/*jslint node: true, browser: true */
/*global $tw: false */
"use strict";

var categories = {
	note: null,
	info: null,
	todo: null,
	important: null,
	tip: null,
	success: null,
	question: null,
	warning: null,
	caution: null,
	fail: null,
	danger: null,
	error: null,
	bug: null,
	example: null,
	snippet: null,
	abstract: null,
	summary: null,
	quote: null,
	cite: null,
	"see-also": "SEE ALSO"
};

// initialize default title string
for(var c in categories) {
	if(!categories[c]) {
		categories[c] = c.toUpperCase();
	}
};

var AdmMarkerCode;

var AdmHeadingRegEx = /^\s*([a-zA-Z-]+[a-zA-Z])([-+]?)(?:\s*$|\s+(.*?)\s*$)/;
function parseHeading(text) {
	var m = text.match(AdmHeadingRegEx);
	if(m) {
		var cat = m[1].toLowerCase();
		if(categories.hasOwnProperty(cat)) {
			return {
				category: cat,
				state: (m[2] || null),
				title: (m[3] || categories[cat])
			};
		}
	}
	return null;
}

// parse through source from startLine until endLine or markup string
function reachBlockEnd(state,startLine,endLine,markup) {
	var nextLine=startLine;
	var pos, mem, max, haveEndMarker=false;

	for(nextLine = startLine; nextLine < endLine; nextLine++) {
		pos = mem = state.bMarks[nextLine] + state.tShift[nextLine];
		max = state.eMarks[nextLine];

		if(pos < max && state.sCount[nextLine] < state.blkIndent) {
			// non-empty line with negative indent should stop the list:
			// - ```
			//  test
			break;
		}

		if(state.src.charCodeAt(pos) !== AdmMarkerCode) { continue; }

		if(state.sCount[nextLine] - state.blkIndent >= 4) {
			// closing fence should be indented less than 4 spaces
			continue;
		}

		pos = state.skipChars(pos,AdmMarkerCode);

		// closing code fence must be at least as long as the opening one
		if(pos - mem < markup.length) { continue; }

		// make sure tail has spaces only
		if(state.skipSpaces(pos) < max) { continue; }

		// found!
		haveEndMarker = true;
		break;
	}

	if(haveEndMarker) {
		nextLine++;
	}

	return { endLine: nextLine, endMarker: (haveEndMarker ? state.src.slice(mem,pos) : "") };
}

module.exports = function admonitionPlugin(md,options) {
	function admonitionRule(state,startLine,endLine,silent) {
		var pos, params, token, markup,
		start = state.bMarks[startLine] + state.tShift[startLine],
		max = state.eMarks[startLine];

		if(start + 3 > max) { return false; }

		if(state.src.charCodeAt(start) !== AdmMarkerCode) {
		  return false;
		}

		// scan marker length, must be >= 3
		pos = state.skipChars(start,AdmMarkerCode);

		if(pos - start < 3) { return false; }

		markup = state.src.slice(start,pos);
		params = state.src.slice(pos,max);

		// parse heading
		var heading = parseHeading(params);
		if(!heading) { return false; }

		// Since start is found, we can report success here in validation mode
		if(silent) { return true; }

		var loop = reachBlockEnd(state,startLine + 1,endLine,markup);
		var oldParent = state.parentType;
		var oldLineMax = state.lineMax;
		state.parentType = 'admonition';

		var blockTag = heading.state ? 'details' : 'div';
		var titleTag = heading.state ? 'summary' : 'div';

		token = state.push('admonition_open',blockTag,1);
		token.markup = markup;
		token.block  = true;
		token.info   = heading.category;
		token.map    = [ startLine, loop.endLine ];
		token.attrJoin('class','admonition');
		token.attrJoin('class',heading.category);
		if(heading.state === '+') {
			token.attrSet('open','open');
		}

		// admonition title
		token = state.push('admonition_title_open',titleTag,1);
		token.markup = markup;
		token.info   = heading.category;
		token.map    = [ startLine, startLine + 1 ];
		token.attrSet('class','admonition-title');

		token = state.push('inline','',0);
		token.content  = heading.title;
		token.map      = [ startLine, startLine + 1 ];
		token.children = [];

		token = state.push('admonition_title_close',titleTag,-1);
		token.markup = markup;
		token.info   = heading.category;

		token = state.push('admonition_body_open','div',1);
		token.attrSet('class','admonition-body');
		token.map = [ startLine + 1, loop.endLine - (loop.endMarker ? 1 : 0) ];

		// this will prevent lazy continuations from ever going past our end marker
		state.lineMax = token.map[1];
		state.md.block.tokenize(state,token.map[0],token.map[1]);

		token  = state.push('admonition_body_close','div',-1);
		token  = state.push('admonition_close',blockTag,-1);
		token.markup = loop.endMarker;
		token.block  = true;

		state.parentType = oldParent;
		state.lineMax = oldLineMax;
		state.line = loop.endLine;

		return true;
	}

	//var defaults = { marker: ":" };

	options = options || {};

	AdmMarkerCode = (options.maker || ":").charCodeAt(0);

	//options = md.utils.assign({},defaults,options);
	//options.markerCode = options.marker.charCodeAt(0);

	md.block.ruler.before('fence','admonition',admonitionRule,{
		alt: [ 'paragraph', 'reference', 'blockquote', 'list' ]
	});
};
})();","type":"application/javascript","module-type":"library"},"$:/plugins/cdr/markdown-more/markdown-it-checklist.js":{"title":"$:/plugins/cdr/markdown-more/markdown-it-checklist.js","text":"/*\
title: $:/plugins/cdr/markdown-more/markdown-it-checklist.js
type: application/javascript
module-type: library

Adds checklist syntax:

```
- [ ] task 1
- [x] task 2
```
\*/
(function(){

/*jslint node: true, browser: true */
/*global $tw: false */
"use strict";

var CheckBoxRegEx = /^\[([xX ])\]\s+/g;

// token[idx] is the first inline token of a list item
function processListItemStart(state,tokens,idx) {
	var tok = tokens[idx]; // inline token
	var blockState = state.md.blockState;

	if(tok.children.length <= 0) { return; }

	var text = tok.children[0].content;

	CheckBoxRegEx.lastIndex = 0;
	var match = CheckBoxRegEx.exec(text);

	if(match) {
		var checked = false;
		if(match[1] === " ") {
			tokens[idx - 2].attrSet("class","checklist-item unchecked");
		} else {
			tokens[idx - 2].attrSet("class","checklist-item checked");
			checked = true;
		}
		tok.children[0].content = text.substring(CheckBoxRegEx.lastIndex);
		var inputToken = new state.Token('checkbox','$md-checkbox',0);
		inputToken.attrSet("class","checklist-item-checkbox");
		inputToken.attrSet("type","checkbox");
		inputToken.attrSet("pos",blockState.bMarks[tokens[idx].map[0]]);
		if(checked) {
			inputToken.attrSet("checked","");
		}
		tok.children.unshift(inputToken);
	}
}

function isListItemStart(tokens,idx) {
	return tokens[idx].type === "inline" &&
		tokens[idx - 1].type == "paragraph_open" &&
		tokens[idx - 2].type === "list_item_open";
}

function processLists(state) {
	var tokens = state.tokens;

	for(var idx = 2; idx < tokens.length; idx++) {
		if(isListItemStart(tokens,idx)) {
			processListItemStart(state,tokens,idx);
		}
	}
	delete state.md.blockState;
}

function checklistPlugin(md,options) {
	md.core.ruler.after('inline','checklist',processLists,options);

	// insert a dummy rule in order to preserve block processing's state object
	md.block.ruler.before('table','_dummy_',function(state,startLine,endLine,silent) {
		state.md.blockState = state;
		return false;
	});
}

module.exports = checklistPlugin;
})();","type":"application/javascript","module-type":"library"},"$:/plugins/cdr/markdown-more/markdown-it-example.js":{"title":"$:/plugins/cdr/markdown-more/markdown-it-example.js","text":"/*\
title: $:/plugins/cdr/markdown-more/markdown-it-example.js
type: application/javascript
module-type: library

Adds example syntax:

```
-> example sentence  // comment
```
\*/

(function(){

/*jslint node: true, browser: true */
/*global $tw: false */
"use strict";

function examplePlugin(md,options) {
	function exampleRule(state,startLine,endLine,silent) {
		var token, ch,
		markup = '->',
		pos = state.bMarks[startLine] + state.tShift[startLine],
		max = state.eMarks[startLine];

  		// if it's indented more than 3 spaces, it should be a code block
  		if(state.sCount[startLine] - state.blkIndent >= 4) { return false; }

		if(pos+1 >= max) { return false; }

		if(state.src.charCodeAt(pos++) !== markup.charCodeAt(0)) { return false; }

		if(state.src.charCodeAt(pos++) !== markup.charCodeAt(1)) { return false; }

		if(pos < max) {
			ch = state.src.charCodeAt(pos);
			if(ch !== 0x09 /* TAB */ && ch !== 0x20 /* space */) { return false; }
		}

		if(silent) {
			return true;
		}

		var terminatorRules = state.md.block.ruler.getRules('paragraph');
		var oldParentType = state.parentType;
		state.parentType = 'paragraph';

		// jump line-by-line until empty one or EOF
		var nextLine = startLine + 1;
		for(; nextLine < endLine && !state.isEmpty(nextLine); nextLine++) {
			// this would be a code block normally, but after paragraph
   	 		// it's considered a lazy continuation regardless of what's there
    		if(state.sCount[nextLine] - state.blkIndent > 3) { continue; }

			// quirk for blockquotes, this line should already be checked by that rule
    		if(state.sCount[nextLine] < 0) { continue; }

			// Some tags can terminate paragraph without empty line.
			let terminate = false;
			for (let i = 0;i < terminatorRules.length;i++) {
				if (terminatorRules[i](state, nextLine, endLine, true)) {
					terminate = true;
					break;
				}
			}
			if (terminate) { break; } 
		}

		var content = state.src.slice(pos + 1,state.eMarks[startLine] + 1) + state.getLines(startLine + 1, nextLine, state.blkIndent, false);
		var comment = null;
		var i = content.indexOf('//');
		if(i != -1) {
			comment = content.slice(i+2).trim();
			content = content.slice(0,i).trim();
		}

		state.line = nextLine;
		state.parentType = oldParentType;

		token = state.push('example_open','div',1);
		token.attrSet('class','md-example-container');
		token.block  = true;
		token.markup = markup;
		token.map = [ startLine, state.line ];

		token = state.push('example_text_open','span',1);
		token.attrSet('class','md-example-text');
		token.map = [ startLine, nextLine ];

		token = state.push('inline','',0);
  		token.content  = content;
  		token.map      = [ startLine, state.line ];
  		token.children = [];

		token = state.push('example_text_close','span',-1);

		if(comment) {
			token = state.push('example_comment_open','span',1);
			token.attrSet('class','md-example-comment');
			token.map = [ startLine, state.line ];

			token = state.push('inline','',0);
			token.content  = comment;
			token.map      = [ startLine, state.line ];
			token.children = [];

			token = state.push('example_comment_close','span',-1);		
		}

		token = state.push('example_close','div',-1);
		token.block  = true;
		token.markup = markup;

		return true;
	}

	md.block.ruler.after('heading','example',exampleRule,{
		alt: [ 'paragraph', 'reference', 'blockquote' ]
	});
}

module.exports = examplePlugin;
})();","type":"application/javascript","module-type":"library"},"$:/plugins/cdr/markdown-more/md-checkbox.js":{"title":"$:/plugins/cdr/markdown-more/md-checkbox.js","text":"/*\
title: $:/plugins/cdr/markdown-more/md-checkbox.js
type: application/javascript
module-type: widget

Interactive checkbox for markdown checklists. Internal use only.
\*/

(function(){

/*jslint node: true, browser: true */
/*global $tw: false */
"use strict";

var Widget = require("$:/core/modules/widgets/widget.js").widget;

var MarkdownCheckboxWidget = function(parseTreeNode,options) {
	this.initialise(parseTreeNode,options);
};

/*
Inherit from the base widget class
*/
MarkdownCheckboxWidget.prototype = new Widget();

/*
Render this widget into the DOM
*/
MarkdownCheckboxWidget.prototype.render = function(parent,nextSibling) {
	this.parentDomNode = parent;
	this.computeAttributes();
	this.execute();

	// create our element
	this.inputNode = this.document.createElement("input");
	this.inputNode.setAttribute("type","checkbox");

	if(this.isChecked) {
		this.inputNode.setAttribute("class","checklist-item-checkbox checked");
		this.inputNode.setAttribute("checked","");
	} else {
		this.inputNode.setAttribute("class","checklist-item-checkbox unchecked");
	}
	if(this.isDisabled) {
		this.inputNode.setAttribute("disabled","");
	} else {
		// add event handler
		$tw.utils.addEventListeners(this.inputNode,[
			{
				name: "change",
				handlerObject: this,
				handlerMethod: "handleChangeEvent"
			}
		]);
	}

	// insert into the DOM
	parent.insertBefore(this.inputNode,nextSibling);
	this.domNodes.push(this.inputNode);
};

/*
Make a best effort to determine if the title of the storyTiddler matches that of
the transcluded tiddler. This function may provide inaccurate result if
the relevant titles contain the "|" character. But TW has a
Title/BadCharacterWarning that reduces the scenario.
*/
function matchTranscludeTitle(storyTiddlerTitle) {
	var curTiddlerTitle = this.getVariable("currentTiddler"),
		transclusion = this.getVariable("transclusion");

	if(transclusion === undefined) {return true;}

	if(transclusion.indexOf(curTiddlerTitle + "|") === 1) {
		var pos = 2 + curTiddlerTitle.length;
		return (transclusion.indexOf(storyTiddlerTitle + "|",pos) === pos);
	}
	return false;
}

/*
Compute the internal state of the widget
*/
MarkdownCheckboxWidget.prototype.execute = function() {
	this.tiddlerTitle = this.getVariable("storyTiddler");

	// Get the parameters from the attributes
	this.pos = parseInt(this.getAttribute("pos"));
	if(! isNaN(this.pos) && this.pos < 0) {
		this.pos = NaN;
	}

	this.isChecked = this.getAttribute("checked") !== undefined;
	this.isDisabled = (this.getAttribute("disabled") !== undefined)
		|| isNaN(this.pos)
		|| ! $tw.wiki.getTiddler(this.tiddlerTitle);

	if(!matchTranscludeTitle.call(this,this.tiddlerTitle)) {
		this.isDisabled = true;
	}
};

/*
Selectively refreshes the widget if needed. Returns true if the widget or any of its children needed re-rendering
*/
MarkdownCheckboxWidget.prototype.refresh = function(changedTiddlers) {
	var changedAttributes = this.computeAttributes();
	if(changedAttributes.pos || changedAttributes.checked || changedAttributes.disabled) {
		this.refreshSelf();
		return true;
	}
	return false;
};

MarkdownCheckboxWidget.prototype.handleChangeEvent = function(event) {
	var newText, text = $tw.wiki.getTiddlerText(this.tiddlerTitle);

	if(text.length <= this.pos) {
		return;
	}
	if(this.inputNode.checked) {
		newText = text.substring(0,this.pos) + text.substring(this.pos).replace(/\[ \]/,"[x]");
		$tw.utils.addClass(this.inputNode,"checked");
		$tw.utils.removeClass(this.inputNode,"unchecked");
	} else {
		newText = text.substring(0,this.pos) + text.substring(this.pos).replace(/\[[xX]\]/,"[ ]");
		$tw.utils.addClass(this.inputNode,"unchecked");
		$tw.utils.removeClass(this.inputNode,"checked");
	}
	$tw.wiki.setText(this.tiddlerTitle,"text",null,newText);
	// Trigger an autosave
	$tw.rootWidget.dispatchEvent({type: "tm-auto-save-wiki"});
}

exports["md-checkbox"] = MarkdownCheckboxWidget;

})();
