* checklist
* example block, an indented block suitable for presenting examples
* admonition
* table of contents, generated from headings in the tiddler

!! Settings

!!! Admonition Style

<$select tiddler="$:/config/markdown/admonition/style" default='classic'><$list filter='[[classic]] [[pastel]]'><option value=<<currentTiddler>>><$view field='title'/></option></$list></$select>

<div class="markdown">
<div class="admonition note" style="margin-top: 1.2em">
<div class="admonition-title">NOTE</div>
<div class="admonition-body">This is an example of an admonition box.</div>
</div>
</div>

!!! Table of Contents

<$checkbox tiddler="$:/config/markdown/toc/enable" field="text" checked="yes" unchecked="no" default="yes">
&#32; generate table of contents
</$checkbox>

<$reveal stateTitle="$:/config/markdown/toc/enable" type="match" text="yes" default="yes">

<$checkbox tiddler="$:/config/markdown/toc/portrait" field="text" checked="hide" unchecked="show" default="hide">
&#32; hide table of contents in portrait/mobile view
</$checkbox>

number of levels:&nbsp;&nbsp;<$select tiddler="$:/config/markdown/toc/depth" default='2'><$list filter='1 2 3'><option value=<<currentTiddler>>><$view field='title'/></option></$list></$select>
</$reveal>"},"$:/plugins/cdr/markdown-more/startup.js":{"title":"$:/plugins/cdr/markdown-more/startup.js","text":"/*\
title: $:/plugins/cdr/markdown-more/startup.js
type: application/javascript
module-type: startup
\*/
(function(){

/*jslint node: true, browser: true */
/*global $tw: false */
"use strict";

// Export name and synchronous status
exports.name = "markdown-more";
exports.after = ["startup"];
exports.before = ["render"];
exports.synchronous = true;

exports.startup = function() {
	var MarkdownParser = $tw.Wiki.parsers["text/markdown"];

	if(!MarkdownParser) { return; }

	var md = MarkdownParser.prototype.md;
	md.use(require("$:/plugins/cdr/markdown-more/markdown-it-checklist.js"))
	  .use(require("$:/plugins/cdr/markdown-more/markdown-it-admonition"))
	  .use(require("$:/plugins/cdr/markdown-more/markdown-it-example"))
	  ;
}
})();
